import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"宇宙星神：盖亚","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/4.B级/宇宙星神：盖亚.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/4.B级/宇宙星神：盖亚.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/4.B级/宇宙星神：盖亚.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"宇宙星神-盖亚",tabindex:"-1"},[p("宇宙星神：盖亚 "),r("a",{class:"header-anchor",href:"#宇宙星神-盖亚","aria-label":'Permalink to "宇宙星神：盖亚"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),n('<h1 id="宇宙星神-盖亚-1" tabindex="-1">宇宙星神：盖亚 <a class="header-anchor" href="#宇宙星神-盖亚-1" aria-label="Permalink to &quot;宇宙星神：盖亚&quot;">​</a></h1><p>宇宙星神：盖亚<br> 介绍：本随从是出自《宇宙星神》世界观中的创世神奥坦以地球为蓝本所创造的机器人战士——地球星神盖亚。也是在所有正义星神中第一个感应到银河之星存在的星神。<br> 主体为白色，身体周围具有青蓝色，具有金属光泽的装甲。<br> 性格善良正直，信念坚定，就算是遇上自己所不能力敌的敌人也会挺身而出。<br> 擅长的武器是“玄铁激光枪”。作为星神的必杀技是“蓝极光剑”。<br> 这个随从可以进行自由行动。</p><p>价格：B+6500<br> ▓▓▓▓基本能力值<br> ▓智力 11<br> ▓感知 11<br> ▓决心 14</p><p>▓力量 16<br> ▓敏捷 14<br> ▓耐力 16</p><p>▓风度 11<br> ▓操控 11<br> ▓沉着 14</p><p>▓▓▓▓技能<br> ▓知识1<br> ▓器用1<br> ▓手艺1<br> ▓专注8 意志8</p><p>▓运动8 反射8<br> ▓生存8 强韧8<br> ▓射击11 步枪11<br> ▓武技11 剑11 拳8</p><p>▓洞察8 搜查8<br> ▓隐秘1<br> ▓表达1<br> ▓社交1</p><p>▓▓▓▓衍生属性值<br> ▓相貌:5<br> ▓体积 11<br> ▓速度 力量16+敏捷14+敏捷附加成功2*3+体积11=47<br> ▓先攻：敏捷14+沉着14=28<br> ▓防御 基础11+2<br> ▓生命值 耐力16+耐力附加成功3*5+体积11=42*1.5=63<br> ▓意志力池28<br> ▓意志 决心14+专注8+意志8=30+5<br> ▓反射 敏捷14+运动8+反射8-环境1=29+5<br> ▓强韧 耐力16+生存8+强韧8+体积1=33+6<br> ▓搜查 感知11+洞察8+搜查8=27+5<br> ▓敏感范围 260<br> ▓▓▓▓攻击预设：<br> 力量16+武技11+拳8+天生武器6L+增强9=50+6<br> 威猛6<br> ▓▓▓▓防御预设：<br> 基防11+2<br> 天生1<br> 盔甲21</p><p>【星神身躯】：宇宙星神是由奥坦制造的机器人战士，所以宇宙星神具有的生命值转为1.5倍的结构值，天生武器具有3L伤害。并且因为注入体内的星际能量，额外获得获得等效于2点快速医疗的2点快速维修（医疗点24）。<br> 因为庞大的体型和重量，宇宙星神进行攻击时额外获得6点威猛。</p><p>【地球装甲】：地球星神盖亚所具有的青蓝色装甲。这视为一件具有18/18盔甲防御和3点盔甲减值的重甲，具有【防能量】特性。</p><p>下属武器：<br> 玄铁激光枪<br> 价格：B+2000<br> 描述：玄铁激光枪是一把具有16L武器伤害，且具有10点高速和【能量武器】特性的步枪。<br> 你可以以一个自由动作，将玄铁激光。枪切换为剑模式在剑模式下，玄铁激光枪是一柄具有20L武器伤害和10破甲的重剑。<br> 【蓄力射击】：在枪模式，你可以以一个整轮动作进行一次蓄力射击，这次射击获得【超级贯穿】，并且这次射击获得6点能量加值和两点附加成功。</p><p>盖亚使用时的攻击预设分别为。<br> 枪模式：敏捷14+射击11+步枪11+武器伤害16L=52+5 10点高速 6威猛<br> 剑模式：力量16+武技11+剑11+武器伤害20L+增强9=67+6 10破甲 6威猛</p><p>星神必杀技（购买后不会获得属性）<br> 蓝极光斩<br> 价格：B+2500<br> 描述：地球星神盖亚的必杀技，在进行光能聚合之后，在玄铁激光枪缠绕上深蓝色的极光，紧接着对敌人发出连续的斩击。<br> 挥舞极光重剑，剑气四溢，代表着正义光辉意志，消灭邪恶。<br> 使用蓝极光斩，你需要以一个移动动作进行“光能聚合”紧接着以一个标准动作使出，合计消耗一个整轮动作。<br> 因为光能聚合带来的庞大能量，你本轮进行的攻击获得14点能量加值，并且具有3点附加成功。<br> 因为蓝极光斩是三次连续的斩击，因此你在本技艺过程中可以进行三次以玄铁激光剑进行的白刃攻击，并选择其中两次为最终攻击结果。<br> 由于剑上缠绕着的极光，本轮中你进行的攻击变为范围攻击，以反射豁免，并且范围是半径15米的扇形。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
